<?php get_header(); $hero_image = get_theme_mod('casa_hero_image'); ?>
<main>
  <section class="hero"><div><p class="eyebrow"><?php echo esc_html(get_theme_mod('casa_hero_label', 'Ciudad Juárez, Chihuahua')); ?></p><h1><?php echo wp_kses_post(nl2br(esc_html(get_theme_mod('casa_hero_title', 'El ritual de compartir.')))); ?></h1><p><?php echo esc_html(get_theme_mod('casa_hero_text', 'Una casa de degustación que celebra la esencia del mezcal y la gastronomía con alma mexicana.')); ?></p><a class="button" href="<?php echo esc_url(get_theme_mod('casa_hero_url', '#secciones')); ?>"><?php echo esc_html(get_theme_mod('casa_hero_button', 'Descubre la experiencia')); ?> ↓</a></div><div class="hero-media"><img src="<?php echo esc_url($hero_image ? wp_get_attachment_image_url($hero_image, 'large') : casa_messer_fallback_image(1)); ?>" alt="<?php esc_attr_e('Casa Messer', 'casa-messer'); ?>"></div></section>
  <section class="home-sections" id="secciones"><div class="intro"><div><p class="eyebrow">DESCUBRE CASA MESSER</p><h2 class="section-title">Una casa, muchas<br><em>formas de vivirla.</em></h2></div><p>Administra estas tarjetas desde el menú <strong>Secciones</strong>: cambia fotografía, título, texto y enlace de cada botón.</p></div><div class="cards"><?php $sections = new WP_Query(array('post_type'=>'messer_section','posts_per_page'=>-1,'orderby'=>'menu_order','order'=>'ASC')); $i=0; while($sections->have_posts()): $sections->the_post(); $label = get_post_meta(get_the_ID(), '_casa_button_label', true) ?: get_the_title(); $url = get_post_meta(get_the_ID(), '_casa_button_url', true) ?: get_permalink(); $class = in_array($i, array(0,6)) ? ' wide' : ''; ?><a class="section-card<?php echo $class; ?>" href="<?php echo esc_url($url); ?>"><?php if(has_post_thumbnail()): the_post_thumbnail('large'); else: ?><img src="<?php echo esc_url(casa_messer_fallback_image($i)); ?>" alt="<?php the_title_attribute(); ?>"><?php endif; ?><span><?php echo esc_html($label); ?> <b>↗</b></span></a><?php $i++; endwhile; wp_reset_postdata(); ?></div></section>
